import './Error.scss';

import { Button } from ':components/Button';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import React from 'react';

import type { ErrorProps } from './Error.types';
import { ErrorImages } from './Error.types';

// Вместо импорта изображений напрямую, используем функцию для получения пути к изображению
// Это позволит загружать изображения по требованию, а не встраивать их в бандл
const getImagePath = (imageName: string) => `/pictures/${imageName}.png`;

const imageMap = {
	[ErrorImages.error403]: getImagePath('403'),
	[ErrorImages.error404]: getImagePath('404'),
	[ErrorImages.error500]: getImagePath('500'),
	[ErrorImages.error502]: getImagePath('502'),
	[ErrorImages.error503]: getImagePath('503'),
	[ErrorImages.gear]: getImagePath('gear'),
	[ErrorImages.radio]: getImagePath('radio'),
};

export const Error: React.FC<ErrorProps> = ({
	title,
	subtitle,
	image,
	actions = 'default',
	className,
	defaultOnBack,
	defaultOnRefresh,
}) => {
	const imagePath = typeof image === 'string' ? image : imageMap[image as ErrorImages];
	const actionsElement =
		actions === 'default' ? (
			<>
				<Button onClick={defaultOnBack}>Назад</Button>
				<Button onClick={defaultOnRefresh} variant={'contained'}>
					Обновить страницу
				</Button>
			</>
		) : (
			actions
		);

	return (
		<div data-testid="Error" className={classNames('error', className)}>
			<img className="error__image" src={imagePath} alt={title || 'Изображение ошибки'} />
			<Typography className="error__title" variant={'h4'}>
				{title}
			</Typography>
			<Typography className="error__subtitle" variant={'body1'}>
				{subtitle}
			</Typography>
			<div className="error__actions">{actions !== 'disabled' && actionsElement}</div>
		</div>
	);
};
